function solve(value: number[], limit: number[]): number {
    const n = value.length;
    const elements: { limit: number, value: number }[] = [];
    for (let i = 0; i < n; i++) {
        elements.push({ limit: limit[i], value: value[i] });
    }
    elements.sort((a, b) => a.limit - b.limit);

    const maxHeap = new MaxHeap<number>();
    let res = 0;
    let active = 0;
    let i = 0;
    while (i < n || !maxHeap.isEmpty()) {
        while (i < n && elements[i].limit <= active) {
            maxHeap.insert(elements[i].value);
            i++;
        }
        if (!maxHeap.isEmpty()) {
            res += maxHeap.extractMax();
            active++;
        } else {
            if (i < n) {
                active = elements[i].limit - 1;
            }
        }
    }
    return res;
}

class MaxHeap<T> {
    private heap: T[] = [];

    constructor() {
        this.heap = [];
    }

    private getParentIndex(index: number): number {
        return Math.floor((index - 1) / 2);
    }

    private getLeftChildIndex(index: number): number {
        return 2 * index + 1;
    }

    private getRightChildIndex(index: number): number {
        return 2 * index + 2;
    }

    private swap(index1: number, index2: number): void {
        [this.heap[index1], this.heap[index2]] = [this.heap[index2], this.heap[index1]];
    }

    private siftUp(index: number): void {
        if (index === 0) return;
        const parentIndex = this.getParentIndex(index);
        if (this.heap[parentIndex] < this.heap[index]) {
            this.swap(parentIndex, index);
            this.siftUp(parentIndex);
        }
    }

    private siftDown(index: number): void {
        const leftChildIndex = this.getLeftChildIndex(index);
        const rightChildIndex = this.getRightChildIndex(index);
        let maxIndex = index;

        if (leftChildIndex < this.heap.length && this.heap[leftChildIndex] > this.heap[maxIndex]) {
            maxIndex = leftChildIndex;
        }

        if (rightChildIndex < this.heap.length && this.heap[rightChildIndex] > this.heap[maxIndex]) {
            maxIndex = rightChildIndex;
        }

        if (maxIndex !== index) {
            this.swap(index, maxIndex);
            this.siftDown(maxIndex);
        }
    }

    public insert(value: T): void {
        this.heap.push(value);
        this.siftUp(this.heap.length - 1);
    }

    public extractMax(): T {
        if (this.heap.length === 0) {
            throw new Error("Heap is empty");
        }
        const max = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.siftDown(0);
        return max;
    }

    public isEmpty(): boolean {
        return this.heap.length === 0;
    }
}
