function solve(value: number[], limit: number[]): number {
    const n = value.length;
    const elements: { limit: number, value: number }[] = [];
    for (let i = 0; i < n; i++) {
        elements.push({ limit: limit[i], value: value[i] });
    }
    elements.sort((a, b) => a.limit - b.limit);

    const maxHeap = new MaxHeap();
    let res = 0;
    let active = 0;
    let i = 0;
    while (i < n || maxHeap.size() > 0) {
        while (i < n && elements[i].limit <= active) {
            maxHeap.push(elements[i].value);
            i++;
        }
        if (maxHeap.size() > 0) {
            res += maxHeap.pop();
            active++;
        } else {
            if (i < n) {
                active = elements[i].limit - 1;
            }
        }
    }
    return res;
}

class MaxHeap {
    private heap: number[];

    constructor() {
        this.heap = [];
    }

    size(): number {
        return this.heap.length;
    }

    push(val: number): void {
        this.heap.push(val);
        this.bubbleUp(this.heap.length - 1);
    }

    pop(): number {
        if (this.heap.length === 0) {
            throw new Error("Heap is empty");
        }
        const max = this.heap[0];
        const end = this.heap.pop();
        if (this.heap.length > 0 && end !== undefined) {
            this.heap[0] = end;
            this.bubbleDown(0);
        }
        return max;
    }

    private bubbleUp(idx: number): void {
        const element = this.heap[idx];
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            const parent = this.heap[parentIdx];
            if (element <= parent) break;
            this.heap[idx] = parent;
            this.heap[parentIdx] = element;
            idx = parentIdx;
        }
    }

    private bubbleDown(idx: number): void {
        const length = this.heap.length;
        const element = this.heap[idx];
        while (true) {
            const leftChildIdx = 2 * idx + 1;
            const rightChildIdx = 2 * idx + 2;
            let leftChild: number | undefined;
            let rightChild: number | undefined;
            let swap: number | null = null;

            if (leftChildIdx < length) {
                leftChild = this.heap[leftChildIdx];
                if (leftChild > element) {
                    swap = leftChildIdx;
                }
            }
            if (rightChildIdx < length) {
                rightChild = this.heap[rightChildIdx];
                if (
